<template><div class="login-page"><div class="login-card"><div class="logo">Smart Ops</div><h2>智能运维工单管理系统</h2><p class="text-muted">请登录后进入系统</p><el-form :model="form" @keyup.enter="handleLogin"><el-form-item><el-input v-model="form.username" placeholder="用户名" size="large" clearable /></el-form-item><el-form-item><el-input v-model="form.password" type="password" placeholder="密码" size="large" show-password /></el-form-item><el-button type="primary" size="large" :loading="loading" style="width:100%" @click="handleLogin">登录</el-button></el-form><div class="tips">请使用系统分配的账号和密码登录</div></div></div></template>
<script setup>import { reactive,ref } from 'vue';import { useRouter } from 'vue-router';import { ElMessage } from 'element-plus';import { useAuthStore } from '../stores/auth';const router=useRouter();const auth=useAuthStore();const loading=ref(false);const form=reactive({username:'',password:''});async function handleLogin(){if(!form.username||!form.password){ElMessage.warning('请输入用户名和密码');return}loading.value=true;try{await auth.login(form);ElMessage.success('登录成功');router.push('/dashboard')}finally{loading.value=false}}</script>
<style scoped>.login-page{min-height:100vh;background:radial-gradient(circle at top left,rgba(37,99,235,.35),transparent 35%),linear-gradient(135deg,#0f172a,#1e293b);display:flex;align-items:center;justify-content:center}.login-card{width:420px;background:#fff;border-radius:22px;padding:36px;box-shadow:0 28px 80px rgba(0,0,0,.25)}.logo{font-size:30px;font-weight:900;color:#2563eb;margin-bottom:14px}.tips{margin-top:18px;color:#94a3b8;font-size:13px}</style>
